#!/usr/bin/env node
// build-extension.js - Build script for Chrome extension with ES6 modules

const fs = require('fs');
const path = require('path');

console.log('Building E-Prime Bias Detector extension...\n');

// Create dist directory
if (!fs.existsSync('dist')) {
  fs.mkdirSync('dist');
}

// Bundle the content script
console.log('Creating bundled content script...');

const bundledContent = `
// E-Prime Bias Detector - Bundled Content Script
// This file is auto-generated by build-extension.js

(function() {
  'use strict';

  const DEBUG_MODE = true;

  function debugLog(...args) {
    if (DEBUG_MODE) {
      console.log('[E-Prime Debug]', ...args);
    }
  }

  // ============================================================================
  // MODULAR COMPONENTS START
  // ============================================================================
  
  ${fs.readFileSync('src/utils/ExcellenceDetector.js', 'utf8')
    .replace(/export\s+class\s+ExcellenceDetector/g, 'class ExcellenceDetector')
    .replace(/^export\s+.*$/gm, '')}
  
  ${fs.readFileSync('src/utils/PerformanceMonitor.js', 'utf8')
    .replace(/export\s+class\s+PerformanceMonitor/g, 'class PerformanceMonitor')
    .replace(/export\s+const\s+performanceMonitor.*$/gm, '')
    .replace(/^export\s+.*$/gm, '')}
  
  ${fs.readFileSync('src/utils/DOMProcessor.js', 'utf8')
    .replace(/export\s+class\s+DOMProcessor/g, 'class DOMProcessor')
    .replace(/^export\s+.*$/gm, '')}
  
  ${fs.readFileSync('src/config/BiasConfig.js', 'utf8')
    .replace(/export\s+class\s+BiasConfig/g, 'class BiasConfig')
    .replace(/^export\s+const.*$/gm, '')
    .replace(/^export\s+.*$/gm, '')}
  
  // ============================================================================
  // DICTIONARIES
  // ============================================================================
  
  ${fs.readFileSync('src/dictionaries/opinion-words.js', 'utf8')
    .replace(/export\s+const\s+opinionWords/g, 'const opinionWords')}
  
  ${fs.readFileSync('src/dictionaries/tobe-verbs.js', 'utf8')
    .replace(/export\s+const\s+toBeVerbs/g, 'const toBeVerbs')}
  
  ${fs.readFileSync('src/dictionaries/absolute-words.js', 'utf8')
    .replace(/export\s+const\s+absoluteWords/g, 'const absoluteWords')}
  
  ${fs.readFileSync('src/dictionaries/passive-patterns.js', 'utf8')
    .replace(/export\s+const\s+passivePatterns/g, 'const passivePatterns')}
  
  ${fs.readFileSync('src/dictionaries/weasel-phrases.js', 'utf8')
    .replace(/export\s+const\s+weaselPhrases/g, 'const weaselPhrases')}
  
  ${fs.readFileSync('src/dictionaries/presupposition-markers.js', 'utf8')
    .replace(/export\s+const\s+presuppositionMarkers/g, 'const presuppositionMarkers')}
  
  ${fs.readFileSync('src/dictionaries/war-metaphors.js', 'utf8')
    .replace(/export\s+const\s+warMetaphors/g, 'const warMetaphors')}
  
  ${fs.readFileSync('src/dictionaries/minimizers.js', 'utf8')
    .replace(/export\s+const\s+minimizers/g, 'const minimizers')}
  
  ${fs.readFileSync('src/dictionaries/maximizers.js', 'utf8')
    .replace(/export\s+const\s+maximizers/g, 'const maximizers')}
  
  ${fs.readFileSync('src/dictionaries/false-balance.js', 'utf8')
    .replace(/export\s+const\s+falseBalancePhrases/g, 'const falseBalancePhrases')}
  
  ${fs.readFileSync('src/dictionaries/euphemisms.js', 'utf8')
    .replace(/export\s+const\s+euphemisms/g, 'const euphemisms')}
  
  ${fs.readFileSync('src/dictionaries/emotional-triggers.js', 'utf8')
    .replace(/export\s+const\s+emotionalTriggers/g, 'const emotionalTriggers')}
  
  ${fs.readFileSync('src/dictionaries/gaslighting.js', 'utf8')
    .replace(/export\s+const\s+gaslightingPhrases/g, 'const gaslightingPhrases')}
  
  ${fs.readFileSync('src/dictionaries/false-dilemma.js', 'utf8')
    .replace(/export\s+const\s+falseDilemmaPhrases/g, 'const falseDilemmaPhrases')}
  
  // BiasPatterns class (from index.js)
  ${fs.readFileSync('src/dictionaries/index.js', 'utf8')
    .replace(/^import\s+.*$/gm, '')
    .replace(/export\s+class\s+BiasPatterns/g, 'class BiasPatterns')
    .replace(/^export\s+\{[^}]*\};?\s*$/gm, '')}
  
  // ============================================================================
  // BIAS DETECTOR
  // ============================================================================
  
  ${fs.readFileSync('src/content/BiasDetector.js', 'utf8')
    .replace(/^import\s+.*$/gm, '')
    .replace(/export\s+class\s+BiasDetector/g, 'class BiasDetector')}
  
  // ============================================================================
  // MAIN CONTENT SCRIPT
  // ============================================================================
  
  ${fs.readFileSync('src/content/content-script.js', 'utf8')
    .replace(/^import\s+.*$/gm, '')
    .replace(/^\(function\(\)\s*\{/, '')
    .replace(/\}\)\(\);?\s*$/, '')}

})();
`;

// Write bundled content script
fs.writeFileSync('dist/content.js', bundledContent);
console.log('✓ Created dist/content.js');

// Copy static files
const filesToCopy = [
  { src: 'manifest.json', dest: 'manifest.json' },
  { src: 'popup.html', dest: 'popup.html' },
  { src: 'popup.js', dest: 'popup.js' },
  { src: 'styles.css', dest: 'styles.css' },
  { src: 'src/excellence-styles.css', dest: 'excellence-styles.css' },
  { src: 'info.html', dest: 'info.html' }
];

filesToCopy.forEach(({ src, dest }) => {
  if (fs.existsSync(src)) {
    fs.copyFileSync(src, path.join('dist', dest));
    console.log(`✓ Copied ${src} → dist/${dest}`);
  } else {
    console.warn(`⚠ Warning: ${src} not found`);
  }
});

// Copy images directory
if (fs.existsSync('images')) {
  const distImages = path.join('dist', 'images');
  if (!fs.existsSync(distImages)) {
    fs.mkdirSync(distImages);
  }
  
  fs.readdirSync('images').forEach(file => {
    fs.copyFileSync(
      path.join('images', file),
      path.join(distImages, file)
    );
  });
  console.log('✓ Copied images directory');
}

// Update manifest.json in dist
const manifestPath = path.join('dist', 'manifest.json');
const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));

// Update paths in manifest
manifest.content_scripts[0].js = ['content.js'];
manifest.content_scripts[0].css = ['styles.css', 'excellence-styles.css'];

fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
console.log('✓ Updated manifest.json paths');

console.log('\n✅ Build complete! Extension ready in dist/ directory');
console.log('\nTo use:');
console.log('1. Open Chrome and go to chrome://extensions/');
console.log('2. Enable "Developer mode"');
console.log('3. Click "Load unpacked"');
console.log('4. Select the dist/ directory');
